16	
17	#include "LongformerAttentionLayer.h"
18	#include "src/fastertransformer/kernels/longformer_kernels.h"
19	
20	#include <cuda_runtime.h>
21	#include <functional>
22	#include <numeric>
23	#include <stdio.h>
24	#include <string>
25	#include <vector>
26	
27	namespace fastertransformer {
28	
29	template<typename T>
30	LongformerAttentionLayer<T>::LongformerAttentionLayer(size_t           head_num,
31	                                                      size_t           size_per_head,
32	                                                      size_t           local_attn_window_size,
33	                                                      size_t           max_global_token_num,
34	                                                      size_t           max_batch_size,
35	                                                      size_t           max_seq_len,
36	                                                      float            attn_scaler,
37	                                                      cudaStream_t     stream,
38	                                                      cublasMMWrapper* cublas_wrapper,
39	                                                      IAllocator*      allocator,
40	                                                      bool             is_free_buffer_after_forward):
41	    BaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward),
42	    head_num_(head_num),
43	    size_per_head_(size_per_head),
44	    local_attn_window_size_(local_attn_window_size),
45	    max_global_token_num_(max_global_token_num),
46	    max_batch_size_(max_batch_size),
47	    max_seq_len_(max_seq_len),
48	    attn_scaler_(attn_scaler)
49	{
50	    FT_CHECK(max_global_token_num_ <= local_attn_window_size_);
51	    check_cuda_error(cudaStreamCreate(&memcpy_stream_));
52	}
53	
54	template<typename T>
55	LongformerAttentionLayer<T>::~LongformerAttentionLayer()
56	{
57	    check_cuda_error(cudaStreamDestroy(memcpy_stream_));
58	    freeBuffer();
59	}
60	
61	template<typename T>
62	void LongformerAttentionLayer<T>::forward(std::vector<Tensor>* output_tensors, const std::vector<Tensor>* input_tensors)
63	{
64	    allocateBuffer();
65	
66	    const int batch_size = input_tensors->at(0).shape[0];
67	    const int seq_len    = input_tensors->at(0).shape[2];
68	    FT_CHECK(seq_len % local_attn_window_size_ == 0);
69	    FT_CHECK(size_per_head_ == 64);
70	
71	    const int batch_stride                            = head_num_ * seq_len * size_per_head_;
72	    const int global_batch_stride                     = head_num_ * max_global_token_num_ * size_per_head_;
73	    const int attn_head_stride                        = seq_len * size_per_head_;
74	    const int attn_window_stride                      = local_attn_window_size_ * size_per_head_;
75	    const int local_attn_head_tail_gemm_strides_count = batch_size * head_num_;
76	    const int local_attn_middle_gemm_strides_count    = (seq_len / local_attn_window_size_) - 2;
77	
78	    const void* q                 = input_tensors->at(0).data;
79	    const void* k                 = input_tensors->at(1).data;
80	    const void* v                 = input_tensors->at(2).data;
81	    const void* qg                = input_tensors->at(3).data;
82	    const void* kg                = input_tensors->at(4).data;
83	    const void* vg                = input_tensors->at(5).data;
84	    const void* local_attn_mask   = input_tensors->at(6).getPtr<const T>();
85	    const void* global_attn_mask  = input_tensors->at(7).getPtr<const T>();
86	    const int*  global_idx        = input_tensors->at(8).getPtr<const int>();
87	    const int*  global_token_nums = input_tensors->at(9).getPtr<const int>();
88	
89	    void* output = (void*)output_tensors->at(0).data;
90	
91	    int global_token_nums_cpu[batch_size];
92	
93	    cudaEvent_t memcpy_finished;
94	    check_cuda_error(cudaEventCreateWithFlags(&memcpy_finished, cudaEventDisableTiming));
95	    check_cuda_error(cudaMemcpyAsync(
96	        global_token_nums_cpu, global_token_nums, batch_size * sizeof(int), cudaMemcpyDeviceToHost, memcpy_stream_));
97	
98	    /*  internal_var sections:
99	      0 - 4: store buf_ptrs which point to buffer 0, 1, 2, 3, 4, respectively. size: 5 * size_t
100	      5 - 9: store buf_sizes for each buffer. size: 5 * size_t
101	      10 - 14: store buf_strides per head for each buffer. size: 5 * size_t
102	    */
103	    size_t* internal_var[15];
104	    void**  buf_ptrs    = (void**)&internal_var[0];
105	    size_t* buf_sizes   = (size_t*)(&internal_var[5]);
106	    size_t* buf_strides = (size_t*)(&internal_var[10]);
107	
108	    buf_sizes[0] = (size_t)local_attn_window_size_ * 2 * local_attn_window_size_;
109	    buf_sizes[1] = (size_t)local_attn_window_size_ * 3 * local_attn_window_size_ * local_attn_middle_gemm_strides_count;
110	    buf_sizes[2] = (size_t)local_attn_window_size_ * 2 * local_attn_window_size_;
111	    buf_sizes[3] = (size_t)local_attn_window_size_ * (seq_len - local_attn_window_size_);
112	    buf_sizes[4] = (size_t)local_attn_window_size_ * seq_len;
113	
114	    buf_strides[0] = (size_t)local_attn_window_size_ * 2;
115	    buf_strides[1] = (size_t)local_attn_window_size_ * 3;
116	    buf_strides[2] = (size_t)local_attn_window_size_ * 2;
117	    buf_strides[3] = (size_t)local_attn_window_size_;
118	    buf_strides[4] = (size_t)seq_len;
119	
120	    /* buffer partition:
121	      0: local attn output per head - head, size:
122	        local_attn_window_size_ * 2 * local_attn_window_size_ * local_attn_head_tail_gemm_strides_count
123	      1: local attn output per head - middle, size:
124	        local_attn_window_size_ * 3 * local_attn_window_size_ * local_attn_middle_gemm_strides_count * batch_size *
125	      head_num_; 2: local attn output per head - tail, size: local_attn_window_size_ * 2 * local_attn_window_size_ *
126	      local_attn_head_tail_gemm_strides_count 3: global part of local k attending q per head, size:
127	        local_attn_window_size_ * (seq_len - local_attn_window_size_)
128	      4: global q attending global k per head, size:
129	        local_attn_window_size_ * seq_len
130	    */
131	
132	    buf_ptrs[0] = attn_buffer_;
133	    for (int i = 1; i < 5; ++i) {
134	        buf_ptrs[i] = (void*)((char*)buf_ptrs[i - 1] + buf_sizes[i - 1] * head_num_ * batch_size * sizeof(T));
135	    }
136	    check_cuda_error(cudaMemcpyAsync(
137	        internal_vars_device_, (void*)internal_var, 15 * sizeof(size_t), cudaMemcpyHostToDevice, memcpy_stream_));
138	    check_cuda_error(cudaEventRecord(memcpy_finished, memcpy_stream_));
139	
140	    // Local attention
141	    // local attn per head - head
142	    cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_T,
143	                                        CUBLAS_OP_N,
144	                                        2 * local_attn_window_size_,
145	                                        local_attn_window_size_,
146	                                        size_per_head_,
147	                                        k,
148	                                        size_per_head_,
149	                                        attn_head_stride,
150	                                        q,
151	                                        size_per_head_,
152	                                        attn_head_stride,
153	                                        buf_ptrs[0],
154	                                        2 * local_attn_window_size_,
155	                                        buf_sizes[0],
156	                                        local_attn_head_tail_gemm_strides_count);
157	
158	    // local attn per head - middle
159	    for (int i = 0; i < batch_size; ++i) {
160	        for (int j = 0; j < (int)head_num_; ++j) {
161	            void* q_middle =
162	                (char*)q
163	                + (i * batch_stride + j * size_per_head_ * seq_len + local_attn_window_size_ * size_per_head_)
164	                      * sizeof(T);
165	            void* k_middle  = (char*)k + (i * batch_stride + j * size_per_head_ * seq_len) * sizeof(T);
166	            void* qk_middle = (char*)buf_ptrs[1] + (i * head_num_ + j) * buf_sizes[1] * sizeof(T);
167	
168	            cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_T,
169	                                                CUBLAS_OP_N,
170	                                                3 * local_attn_window_size_,
171	                                                local_attn_window_size_,
172	                                                size_per_head_,
173	                                                k_middle,
174	                                                size_per_head_,
175	                                                attn_window_stride,
176	                                                q_middle,
177	                                                size_per_head_,
178	                                                attn_window_stride,
179	                                                qk_middle,
180	                                                3 * local_attn_window_size_,
181	                                                3 * local_attn_window_size_ * local_attn_window_size_,
182	                                                local_attn_middle_gemm_strides_count);
183	        }
184	    }
185	
186	    // local attn per head - tail
187	    int   tail_blk_q = (seq_len / local_attn_window_size_) - 1;
188	    int   tail_blk_k = (seq_len / local_attn_window_size_) - 2;
189	    void* q_tail     = (char*)q + tail_blk_q * local_attn_window_size_ * size_per_head_ * sizeof(T);
190	    void* k_tail     = (char*)k + tail_blk_k * local_attn_window_size_ * size_per_head_ * sizeof(T);
191	
192	    cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_T,
193	                                        CUBLAS_OP_N,
194	                                        2 * local_attn_window_size_,
195	                                        local_attn_window_size_,
196	                                        size_per_head_,
197	                                        k_tail,
198	                                        size_per_head_,
199	                                        attn_head_stride,
200	                                        q_tail,
201	                                        size_per_head_,
202	                                        attn_head_stride,
203	                                        buf_ptrs[2],
204	                                        2 * local_attn_window_size_,
205	                                        buf_sizes[2],
206	                                        local_attn_head_tail_gemm_strides_count);
207	
208	    check_cuda_error(cudaEventSynchronize(memcpy_finished));
209	    // global attention
210	    for (int i = 0; i < batch_size; ++i) {
211	        if (global_token_nums_cpu[i] > (int)local_attn_window_size_) {
212	            std::cerr << "ERROR! the number of global tokens are larger than the attention window";
213	            std::cerr << ", the code will not work correctly!!";
214	        }
215	        if (global_token_nums_cpu[i] > 0) {
216	            // local tokens attending global tokens
217	            void* q_local  = (char*)q + (i * batch_stride + local_attn_window_size_ * size_per_head_) * sizeof(T);
218	            void* k_local  = (char*)k + i * batch_stride * sizeof(T);
219	            void* qk_local = (char*)buf_ptrs[3] + i * buf_sizes[3] * head_num_ * sizeof(T);
220	
221	            cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_T,
222	                                                CUBLAS_OP_N,
223	                                                global_token_nums_cpu[i],
224	                                                seq_len - local_attn_window_size_,
225	                                                size_per_head_,
226	                                                k_local,
227	                                                size_per_head_,
228	                                                attn_head_stride,
229	                                                q_local,
230	                                                size_per_head_,
231	                                                attn_head_stride,
232	                                                qk_local,
233	                                                local_attn_window_size_,
234	                                                buf_sizes[3],
235	                                                head_num_);
236	
237	            // global token attending everything
238	            void* q_global  = (char*)qg + (i * global_batch_stride) * sizeof(T);
239	            void* k_global  = (char*)kg + (i * batch_stride) * sizeof(T);
240	            void* qk_global = (char*)buf_ptrs[4] + (i * buf_sizes[4] * head_num_) * sizeof(T);
241	            cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_T,
242	                                                CUBLAS_OP_N,
243	                                                seq_len,
244	                                                global_token_nums_cpu[i],
245	                                                size_per_head_,
246	                                                k_global,
247	                                                size_per_head_,
248	                                                attn_head_stride,
249	                                                q_global,
250	                                                size_per_head_,
251	                                                max_global_token_num_ * size_per_head_,
252	                                                qk_global,
253	                                                seq_len,
254	                                                buf_sizes[4],
255	                                                head_num_);
256	        }
257	    }
258	
259	    invokeLongformerMHASoftmax((const T*)global_attn_mask,
260	                               global_idx,
261	                               global_token_nums,
262	                               internal_vars_device_,
263	                               (const T*)local_attn_mask,
264	                               attn_scaler_,
265	                               seq_len,
266	                               head_num_,
267	                               batch_size,
268	                               local_attn_window_size_,
269	                               stream_);
270	    sync_check_cuda_error();
271	
272	    // local values attending the softmax score.
273	    // local attn per head - head
274	    cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_N,
275	                                        CUBLAS_OP_N,
276	                                        size_per_head_,
277	                                        local_attn_window_size_,
278	                                        2 * local_attn_window_size_,
279	                                        v,
280	                                        size_per_head_,
281	                                        seq_len * size_per_head_,
282	                                        buf_ptrs[0],
283	                                        buf_strides[0],
284	                                        buf_sizes[0],
285	                                        output,
286	                                        size_per_head_,
287	                                        seq_len * size_per_head_,
288	                                        batch_size * head_num_);
289	
290	    // local attn per head - middle
291	    for (int i = 0; i < batch_size; ++i) {
292	        for (int j = 0; j < (int)head_num_; ++j) {
293	            void* v_local = (char*)v + (i * batch_stride + j * size_per_head_ * seq_len) * sizeof(T);
294	            void* prob    = (char*)buf_ptrs[1] + (i * head_num_ + j) * buf_sizes[1] * sizeof(T);
295	            void* out     = (char*)output
296	                        + (i * batch_stride + j * size_per_head_ * seq_len + local_attn_window_size_ * size_per_head_)
297	                              * sizeof(T);
298	            cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_N,
299	                                                CUBLAS_OP_N,
300	                                                size_per_head_,
301	                                                local_attn_window_size_,
302	                                                3 * local_attn_window_size_,
303	                                                v_local,
304	                                                size_per_head_,
305	                                                local_attn_window_size_ * size_per_head_,
306	                                                prob,
307	                                                buf_strides[1],
308	                                                3 * local_attn_window_size_ * local_attn_window_size_,
309	                                                out,
310	                                                size_per_head_,
311	                                                local_attn_window_size_ * size_per_head_,
312	                                                local_attn_middle_gemm_strides_count);
313	        }
314	    }
315	
316	    // local attn per head - tail
317	    int   tail_blk_v   = (seq_len / local_attn_window_size_) - 2;
318	    int   tail_blk_out = (seq_len / local_attn_window_size_) - 1;
319	    void* tail_v       = (char*)v + tail_blk_v * local_attn_window_size_ * size_per_head_ * sizeof(T);
320	    void* tail_out     = (char*)output + tail_blk_out * local_attn_window_size_ * size_per_head_ * sizeof(T);
321	    cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_N,
322	                                        CUBLAS_OP_N,
323	                                        size_per_head_,
324	                                        local_attn_window_size_,
325	                                        2 * local_attn_window_size_,
326	                                        tail_v,
327	                                        size_per_head_,
328	                                        seq_len * size_per_head_,
329	                                        buf_ptrs[2],
330	                                        buf_strides[2],
331	                                        buf_sizes[2],
332	                                        tail_out,
333	                                        size_per_head_,
334	                                        seq_len * size_per_head_,
335	                                        batch_size * head_num_);
336	
337	    // global attention part
338	    for (int i = 0; i < batch_size; ++i) {
339	        if (global_token_nums_cpu[i] > 0) {
340	            int glob_longdim_mm = seq_len - 2 * local_attn_window_size_;
341	
342	            void* v_local = (char*)v + (i * batch_stride) * sizeof(T);
343	            void* prob    = (char*)buf_ptrs[3]
344	                         + (i * buf_sizes[3] * head_num_ + local_attn_window_size_ * buf_strides[3]) * sizeof(T);
345	            void* out = (char*)output + (i * batch_stride + 2 * local_attn_window_size_ * size_per_head_) * sizeof(T);
346	
347	            cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_N,
348	                                                CUBLAS_OP_N,
349	                                                size_per_head_,
350	                                                glob_longdim_mm,
351	                                                global_token_nums_cpu[i],
352	                                                v_local,
353	                                                size_per_head_,
354	                                                seq_len * size_per_head_,
355	                                                prob,
356	                                                buf_strides[3],
357	                                                buf_sizes[3],
358	                                                out,
359	                                                size_per_head_,
360	                                                seq_len * size_per_head_,
361	                                                head_num_,
362	                                                1.0f,
363	                                                1.0f);
364	
365	            // global tokens
366	            void* v_global = (char*)vg + (i * batch_stride) * sizeof(T);
367	            prob           = (char*)buf_ptrs[4] + (i * buf_sizes[4] * head_num_) * sizeof(T);
368	            out            = (char*)output + (i * batch_stride) * sizeof(T);
369	
370	            cublas_wrapper_->stridedBatchedGemm(CUBLAS_OP_N,
371	                                                CUBLAS_OP_N,
372	                                                size_per_head_,
373	                                                global_token_nums_cpu[i],
374	                                                seq_len,
375	                                                v_global,
376	                                                size_per_head_,
377	                                                seq_len * size_per_head_,
378	                                                prob,
379	                                                buf_strides[4],
380	                                                buf_sizes[4],
381	                                                out,
382	                                                size_per_head_,
383	                                                seq_len * size_per_head_,
384	                                                head_num_);
385	        }
386	    }
387	
388	    check_cuda_error(cudaEventDestroy(memcpy_finished));
389	    if (is_free_buffer_after_forward_ == true) {
390	        freeBuffer();
391	    }
392	}
393	
394	template<typename T>
395	void LongformerAttentionLayer<T>::allocateBuffer()
396	{
397	    if (!is_allocate_buffer_) {
398	
399	        internal_vars_device_ = (void*)allocator_->reMalloc(internal_vars_device_, sizeof(size_t) * 15);
400	
401	        attn_buffer_ =
402	            (T*)allocator_->reMalloc(attn_buffer_,
403	                                     sizeof(T) * head_num_ * max_batch_size_
404	                                         * (2 * local_attn_window_size_ * local_attn_window_size_
405	                                            + 3 * local_attn_window_size_ * local_attn_window_size_
406	                                                  * (max_seq_len_ / local_attn_window_size_ - 2)
407	                                            + 2 * local_attn_window_size_ * local_attn_window_size_
408	                                            + local_attn_window_size_ * (max_seq_len_ - local_attn_window_size_)
409	                                            + local_attn_window_size_ * max_seq_len_),
410	                                     false);
411	
412	        is_allocate_buffer_ = true;
413	    }
414	}
415	
416	template<typename T>
417	void LongformerAttentionLayer<T>::freeBuffer()
418	{
419	    if (is_allocate_buffer_) {
420	        allocator_->free((void**)(&internal_vars_device_));
421	        allocator_->free((void**)(&attn_buffer_));
422	
423	        is_allocate_buffer_ = false;
424	    }
425	}
426	
427	template class LongformerAttentionLayer<float>;
428	template class LongformerAttentionLayer<half>;
429	#ifdef ENABLE_BF16
430	template class LongformerAttentionLayer<__nv_bfloat16>;
431	#endif
432	
433	}  // namespace fastertransformer

