18	#include "src/fastertransformer/th_op/th_utils.h"
19	
20	namespace ft = fastertransformer;
21	namespace th = torch;
22	namespace torch_ext {
23	
24	class FasterTransformerLongformerEncoder: public th::jit::CustomClassHolder {
25	private:
26	    size_t layer_num_;
27	    size_t in_dim_;
28	    size_t head_num_;
29	    size_t size_per_head_;
30	    size_t intermediate_size_;
31	    size_t local_attn_window_size_;
32	    size_t max_global_token_num_;
33	    size_t max_batch_size_;
34	    size_t max_seq_len_;
35	    float  attn_scaler_;
36	    size_t hidden_units_;
37	
38	    cublasLtHandle_t   _cublasltHandle;
39	    ft::cublasAlgoMap* cublas_algo_map_;
40	    std::mutex*        cublas_wrapper_mutex_;
41	
42	public:
43	    FasterTransformerLongformerEncoder(int64_t layer_num,
44	                                       int64_t in_dim,
45	                                       int64_t head_num,
46	                                       int64_t size_per_head,
47	                                       int64_t intermediate_size,
48	                                       int64_t local_attn_window_size,
49	                                       int64_t max_global_token_num,
50	                                       int64_t max_batch_size,
51	                                       int64_t max_seq_len,
52	                                       double  attn_scaler);
53	
54	    ~FasterTransformerLongformerEncoder();
55	
56	    th::Tensor forward(th::Tensor input,
57	                       th::Tensor local_attn_mask,
58	                       th::Tensor global_attn_mask,
59	                       th::Tensor th_weights,
60	                       int64_t    device_id = 0);
61	
62	    template<typename T>
63	    void setWeight(int                                        layer_num,
64	                   int                                        in_dim,
65	                   int                                        hidden_units,
66	                   int                                        intermediate_size,
67	                   th::Tensor                                 th_weights,
68	                   std::vector<ft::LongformerLayerWeight<T>>* weights)
69	    {
70	        weights->clear();
71	        weights->resize(layer_num);
72	        auto weights_ptr = get_ptr<T>(th_weights);
73	        int  offside     = 0;
74	        for (int i = 0; i < layer_num; i++) {
75	            // q k v kg vg weights and bias should be continuous, required by the ft longformer encoder.
76	            weights->at(i).query_weights.kernel = weights_ptr + offside;  // q
77	            offside += (i == 0 ? in_dim : hidden_units) * hidden_units;
78	            weights->at(i).key_weights.kernel = weights_ptr + offside;  // k
79	            offside += (i == 0 ? in_dim : hidden_units) * hidden_units;
80	            weights->at(i).value_weights.kernel = weights_ptr + offside;  // v
81	            offside += (i == 0 ? in_dim : hidden_units) * hidden_units;
82	            weights->at(i).global_key_weights.kernel = weights_ptr + offside;  // kg
83	            offside += (i == 0 ? in_dim : hidden_units) * hidden_units;
84	            weights->at(i).global_value_weights.kernel = weights_ptr + offside;  // vg
85	            offside += (i == 0 ? in_dim : hidden_units) * hidden_units;
86	
87	            weights->at(i).global_query_weights.kernel = weights_ptr + offside;  // qg
88	            offside += (i == 0 ? in_dim : hidden_units) * hidden_units;
89	
90	            weights->at(i).query_weights.bias = weights_ptr + offside;  // q
91	            offside += hidden_units;
92	            weights->at(i).key_weights.bias = weights_ptr + offside;  // k
93	            offside += hidden_units;
94	            weights->at(i).value_weights.bias = weights_ptr + offside;  // v
95	            offside += hidden_units;
96	            weights->at(i).global_key_weights.bias = weights_ptr + offside;  // kg
97	            offside += hidden_units;
98	            weights->at(i).global_value_weights.bias = weights_ptr + offside;  // vg
99	            offside += hidden_units;
100	
101	            weights->at(i).global_query_weights.bias = weights_ptr + offside;  // qg
102	            offside += hidden_units;
103	
104	            weights->at(i).attention_output_weights.kernel = weights_ptr + offside;  // attn output
105	            offside += hidden_units * hidden_units;
106	            weights->at(i).attention_output_weights.bias = weights_ptr + offside;  // attn output
107	            offside += hidden_units;
108	
109	            weights->at(i).attention_output_layernorm_weights.gamma = weights_ptr + offside;  // attn output layernorm
110	            offside += hidden_units;
111	            weights->at(i).attention_output_layernorm_weights.beta = weights_ptr + offside;  // attn output layernorm
112	            offside += hidden_units;
113	
114	            weights->at(i).ffn_weights.intermediate_weight.kernel = weights_ptr + offside;  // inter
115	            offside += hidden_units * intermediate_size;
116	            weights->at(i).ffn_weights.intermediate_weight.bias = weights_ptr + offside;  // inter
117	            offside += intermediate_size;
118	
119	            weights->at(i).ffn_weights.output_weight.kernel = weights_ptr + offside;  // output
120	            offside += hidden_units * intermediate_size;
121	            weights->at(i).ffn_weights.output_weight.bias = weights_ptr + offside;  // output
122	            offside += hidden_units;
123	
124	            weights->at(i).output_layernorm_weights.gamma = weights_ptr + offside;  // output layernorm
125	            offside += hidden_units;
126	            weights->at(i).output_layernorm_weights.beta = weights_ptr + offside;  // output layernorm
127	            offside += hidden_units;
128	        }
129	    }
130	};
